-- Satınalma faturaları (ALIS/ALIS_IADE) + kalemler + stok hareketleri (ambar 01)
BEGIN;

-- Faturalar
ON CONFLICT (id) DO UPDATE SET "tenantId" = EXCLUDED."tenantId", "faturaNo" = EXCLUDED."faturaNo", tarih = EXCLUDED.tarih, "updatedAt" = EXCLUDED."updatedAt";

-- Fatura kalemleri
ON CONFLICT (id) DO UPDATE SET "faturaId" = EXCLUDED."faturaId", "stokId" = EXCLUDED."stokId", miktar = EXCLUDED.miktar, "birimFiyat" = EXCLUDED."birimFiyat";

-- Stok hareketleri (ambar 01)
ON CONFLICT (id) DO UPDATE SET miktar = EXCLUDED.miktar, "birimFiyat" = EXCLUDED."birimFiyat";

COMMIT;
